// NewCreateDraftRequestBody builds the HTTP request body from the payload of
// the "createDraft" endpoint of the "corpus" service.
func NewCreateDraftRequestBody(p *corpus.CreateDraftPayload) *CreateDraftRequestBody {
	body := &CreateDraftRequestBody{
		FilePath:        p.FilePath,
		Title:           p.Title,
		Content:         p.Content,
		OriginalContent: p.OriginalContent,
		Operation:       p.Operation,
		Source:          p.Source,
		AuthorType:      p.AuthorType,
		AuthorUserID:    p.AuthorUserID,
		AgentName:       p.AgentName,
	}
	if p.Labels != nil {
		body.Labels = make([]string, len(p.Labels))
		for i, val := range p.Labels {
			body.Labels[i] = val
		}
	}
	return body
}

